import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate, useLocation } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import MicrosoftTeams from './components/MicrosoftTeams';
import Zoom from './components/Zoom';
import Skype from './components/Skype';
import MicrosoftWord from './components/MicrosoftWord';
import MicrosoftExcel from './components/MicrosoftExcel';
import PowerPoint from './components/PowerPoint';
import PDFReader from './components/PDF';
import Chrome from './components/chrome';
import WhatsApp from './components/WhatsApp';
import FileExplorer from './components/FileExplorer';
import './App.css';

const MainContent = ({ activeComponent, setActiveComponent }) => {
  const navigate = useNavigate(); // Hook pentru navigare
  const location = useLocation(); // Hook pentru locația curentă

  // Dacă există o rută activă (cum ar fi Teams, Zoom, Skype), ignorăm activeComponent
  const isRouteActive = location.pathname.startsWith('/shortcuts/teams') || 
                        location.pathname.startsWith('/shortcuts/zoom') || 
                        location.pathname.startsWith('/shortcuts/skype');

  // Funcție care resetează ruta când se alege o componentă activă
  const handleSetActiveComponent = (component) => {
    setActiveComponent(component);
    navigate('/shortcuts'); // Navigăm la /shortcuts pentru a afișa componentele active
  };

  return (
    <div className="content">
      <Routes>
        {/* Rute pentru Teams, Zoom și Skype */}
        <Route path="/shortcuts/teams" element={<MicrosoftTeams />} />
        <Route path="/shortcuts/zoom" element={<Zoom />} />
        <Route path="/shortcuts/skype" element={<Skype />} />

        {/* Redăm componentele gestionate prin activeComponent doar pe ruta /shortcuts */}
        <Route path="/shortcuts" element={
          !isRouteActive && (
            <>
              {activeComponent === 'fileExplorer' && <FileExplorer setActiveComponent={handleSetActiveComponent} />}
              {activeComponent === 'microsoftWord' && <MicrosoftWord setActiveComponent={handleSetActiveComponent} />}
              {activeComponent === 'microsoftExcel' && <MicrosoftExcel setActiveComponent={handleSetActiveComponent} />}
              {activeComponent === 'powerPoint' && <PowerPoint setActiveComponent={handleSetActiveComponent} />}
              {activeComponent === 'pdfReader' && <PDFReader setActiveComponent={handleSetActiveComponent} />}
              {activeComponent === 'chrome' && <Chrome setActiveComponent={handleSetActiveComponent} />}
              {activeComponent === 'whatsapp' && <WhatsApp setActiveComponent={handleSetActiveComponent} />}
            </>
          )
        } />
      </Routes>
    </div>
  );
};

const App = () => {
  const [activeComponent, setActiveComponent] = useState('fileExplorer');

  return (
    <Router>
      <div className="App">
        <Sidebar setActiveComponent={setActiveComponent} />
        <MainContent activeComponent={activeComponent} setActiveComponent={setActiveComponent} />
      </div>
    </Router>
  );
};

export default App;
